import { describe, it, expect, expectTypeOf } from "vitest";
import type { ModelMessage } from "ai";
import type {
  Message,
  CheckpointMessage,
  SessionMetadata,
  CompactionConfig,
  PruningConfig,
  ContinuationVariant,
  CompactionResult,
  PreparedCompactionV2,
  ActualTokenUsage,
  ActualTokenUsageInput,
  ContextUsage,
  TodoItem,
  StructuredState,
  SessionHeaderLine,
  MessageLine,
  CheckpointLine,
  SessionFileLine,
  CompactionSummary,
  CompactionSegment,
  PreparedCompactionSegment,
  PreparedCompaction,
} from "./compaction-types";

describe("compaction-types", () => {
  // ============================================
  // 1. Message Interface
  // ============================================
  describe("Message", () => {
    it("should have required fields: createdAt, id, modelMessage", () => {
      const message: Message = {
        createdAt: new Date(),
        id: "msg-123",
        modelMessage: { role: "user", content: "Hello" },
      };
      expect(message.createdAt).toBeInstanceOf(Date);
      expect(message.id).toBe("msg-123");
      expect(message.modelMessage).toBeDefined();
    });

    it("should allow optional originalContent field", () => {
      const message: Message = {
        createdAt: new Date(),
        id: "msg-123",
        modelMessage: { role: "user", content: "Hello" },
        originalContent: "original text",
      };
      expect(message.originalContent).toBe("original text");
    });

    it("should reject when required fields are missing", () => {
      // @ts-expect-error - missing required fields
      const invalidMessage: Message = {};
      expect(invalidMessage).toBeDefined();
    });

    it("should have correct types for each field", () => {
      expectTypeOf<Message["createdAt"]>().toEqualTypeOf<Date>();
      expectTypeOf<Message["id"]>().toEqualTypeOf<string>();
      expectTypeOf<Message["modelMessage"]>().toEqualTypeOf<ModelMessage>();
      expectTypeOf<Message["originalContent"]>().toEqualTypeOf<string | undefined>();
    });

    it("should support type compatibility with optional fields", () => {
      const baseMessage: Message = {
        createdAt: new Date(),
        id: "msg-123",
        modelMessage: { role: "user", content: "Hello" },
      };
      const extendedMessage: Message = {
        ...baseMessage,
        originalContent: "original",
      };
      expect(extendedMessage.originalContent).toBe("original");
    });
  });

  // ============================================
  // 2. CheckpointMessage Interface
  // ============================================
  describe("CheckpointMessage", () => {
    it("should have required fields: createdAt, id, isSummary, message", () => {
      const checkpoint: CheckpointMessage = {
        createdAt: Date.now(),
        id: "cp-123",
        isSummary: false,
        message: { role: "assistant", content: "Response" },
      };
      expect(checkpoint.createdAt).toBeDefined();
      expect(checkpoint.id).toBe("cp-123");
      expect(checkpoint.isSummary).toBe(false);
      expect(checkpoint.message).toBeDefined();
    });

    it("should allow optional isSummaryMessage field", () => {
      const checkpoint: CheckpointMessage = {
        createdAt: Date.now(),
        id: "cp-123",
        isSummary: true,
        isSummaryMessage: true,
        message: { role: "system", content: "Summary" },
      };
      expect(checkpoint.isSummaryMessage).toBe(true);
    });

    it("should allow optional originalContent field", () => {
      const checkpoint: CheckpointMessage = {
        createdAt: Date.now(),
        id: "cp-123",
        isSummary: false,
        message: { role: "assistant", content: "Response" },
        originalContent: "original response",
      };
      expect(checkpoint.originalContent).toBe("original response");
    });

    it("should reject when required fields are missing", () => {
      // @ts-expect-error - missing required fields
      const invalidCheckpoint: CheckpointMessage = {};
      expect(invalidCheckpoint).toBeDefined();
    });

    it("should have correct types for each field", () => {
      expectTypeOf<CheckpointMessage["createdAt"]>().toEqualTypeOf<number>();
      expectTypeOf<CheckpointMessage["id"]>().toEqualTypeOf<string>();
      expectTypeOf<CheckpointMessage["isSummary"]>().toEqualTypeOf<boolean>();
      expectTypeOf<CheckpointMessage["isSummaryMessage"]>().toEqualTypeOf<boolean | undefined>();
      expectTypeOf<CheckpointMessage["message"]>().toEqualTypeOf<ModelMessage>();
      expectTypeOf<CheckpointMessage["originalContent"]>().toEqualTypeOf<string | undefined>();
    });
  });

  // ============================================
  // 3. SessionMetadata Interface
  // ============================================
  describe("SessionMetadata", () => {
    it("should have all required fields", () => {
      const metadata: SessionMetadata = {
        completionTokens: 100,
        createdAt: Date.now(),
        promptTokens: 50,
        sessionId: "session-123",
        summaryMessageId: null,
        updatedAt: Date.now(),
      };
      expect(metadata.completionTokens).toBe(100);
      expect(metadata.createdAt).toBeDefined();
      expect(metadata.promptTokens).toBe(50);
      expect(metadata.sessionId).toBe("session-123");
      expect(metadata.summaryMessageId).toBeNull();
      expect(metadata.updatedAt).toBeDefined();
    });

    it("should allow setting summaryMessageId to a string", () => {
      const metadata: SessionMetadata = {
        completionTokens: 100,
        createdAt: Date.now(),
        promptTokens: 50,
        sessionId: "session-123",
        summaryMessageId: "summary-456",
        updatedAt: Date.now(),
      };
      expect(metadata.summaryMessageId).toBe("summary-456");
    });

    it("should reject when required fields are missing", () => {
      // @ts-expect-error - missing required fields
      const invalidMetadata: SessionMetadata = {};
      expect(invalidMetadata).toBeDefined();
    });

    it("should have correct types for each field", () => {
      expectTypeOf<SessionMetadata["completionTokens"]>().toEqualTypeOf<number>();
      expectTypeOf<SessionMetadata["createdAt"]>().toEqualTypeOf<number>();
      expectTypeOf<SessionMetadata["promptTokens"]>().toEqualTypeOf<number>();
      expectTypeOf<SessionMetadata["sessionId"]>().toEqualTypeOf<string>();
      expectTypeOf<SessionMetadata["summaryMessageId"]>().toEqualTypeOf<string | null>();
      expectTypeOf<SessionMetadata["updatedAt"]>().toEqualTypeOf<number>();
    });
  });

  // ============================================
  // 4. CompactionConfig Interface
  // ============================================
  describe("CompactionConfig", () => {
    it("should allow empty config with all optional fields", () => {
      const config: CompactionConfig = {};
      expect(config).toBeDefined();
    });

    it("should accept contextLimit option", () => {
      const config: CompactionConfig = {
        contextLimit: 128000,
      };
      expect(config.contextLimit).toBe(128000);
    });

    it("should accept enabled option", () => {
      const config: CompactionConfig = {
        enabled: true,
      };
      expect(config.enabled).toBe(true);
    });

    it("should accept getStructuredState callback", () => {
      const config: CompactionConfig = {
        getStructuredState: () => "state data",
      };
      expect(config.getStructuredState).toBeDefined();
      expect(config.getStructuredState!()).toBe("state data");
    });

    it("should accept getStructuredState returning undefined", () => {
      const config: CompactionConfig = {
        getStructuredState: () => undefined,
      };
      expect(config.getStructuredState).toBeDefined();
      expect(config.getStructuredState!()).toBeUndefined();
    });

    it("should accept keepRecentTokens option", () => {
      const config: CompactionConfig = {
        keepRecentTokens: 2000,
      };
      expect(config.keepRecentTokens).toBe(2000);
    });

    it("should accept maxTokens option", () => {
      const config: CompactionConfig = {
        maxTokens: 8000,
      };
      expect(config.maxTokens).toBe(8000);
    });

    it("should accept reserveTokens option", () => {
      const config: CompactionConfig = {
        reserveTokens: 2000,
      };
      expect(config.reserveTokens).toBe(2000);
    });

    it("should accept speculativeStartRatio option", () => {
      const config: CompactionConfig = {
        speculativeStartRatio: 0.5,
      };
      expect(config.speculativeStartRatio).toBe(0.5);
    });

    it("should accept summarizeFn callback", () => {
      const config: CompactionConfig = {
        summarizeFn: async (messages) => "summary",
      };
      expect(config.summarizeFn).toBeDefined();
    });

    it("should accept thresholdRatio option", () => {
      const config: CompactionConfig = {
        thresholdRatio: 0.5,
      };
      expect(config.thresholdRatio).toBe(0.5);
    });

    it("should reject when required fields are missing", () => {
      // @ts-expect-error - missing required fields (all fields are optional)
      const invalidConfig: CompactionConfig = {};
      expect(invalidConfig).toBeDefined();
    });

    it("should have correct types for each field", () => {
      expectTypeOf<CompactionConfig["contextLimit"]>().toEqualTypeOf<number | undefined>();
      expectTypeOf<CompactionConfig["enabled"]>().toEqualTypeOf<boolean | undefined>();
      expectTypeOf<CompactionConfig["getStructuredState"]>().toEqualTypeOf<(() => string | undefined) | undefined>();
      expectTypeOf<CompactionConfig["keepRecentTokens"]>().toEqualTypeOf<number | undefined>();
      expectTypeOf<CompactionConfig["maxTokens"]>().toEqualTypeOf<number | undefined>();
      expectTypeOf<CompactionConfig["reserveTokens"]>().toEqualTypeOf<number | undefined>();
      expectTypeOf<CompactionConfig["speculativeStartRatio"]>().toEqualTypeOf<number | undefined>();
      expectTypeOf<CompactionConfig["summarizeFn"]>().toEqualTypeOf<((messages: ModelMessage[], previousSummary?: string) => Promise<string>) | undefined>();
      expectTypeOf<CompactionConfig["thresholdRatio"]>().toEqualTypeOf<number | undefined>();
    });

    it("should support default values through partial config", () => {
      const config: CompactionConfig = {
        contextLimit: 128000,
        enabled: false,
        keepRecentTokens: 2000,
        maxTokens: 8000,
        reserveTokens: 2000,
        speculativeStartRatio: 0.5,
        thresholdRatio: 0.5,
      };
      expect(config.contextLimit).toBe(128000);
      expect(config.enabled).toBe(false);
      expect(config.keepRecentTokens).toBe(2000);
      expect(config.maxTokens).toBe(8000);
      expect(config.reserveTokens).toBe(2000);
      expect(config.speculativeStartRatio).toBe(0.5);
      expect(config.thresholdRatio).toBe(0.5);
    });
  });

  // ============================================
  // 5. PruningConfig Interface
  // ============================================
  describe("PruningConfig", () => {
    it("should allow empty config with all optional fields", () => {
      const config: PruningConfig = {};
      expect(config).toBeDefined();
    });

    it("should accept eagerPruneToolNames option", () => {
      const config: PruningConfig = {
        eagerPruneToolNames: ["tool1", "tool2"],
      };
      expect(config.eagerPruneToolNames).toEqual(["tool1", "tool2"]);
    });

    it("should accept enabled option", () => {
      const config: PruningConfig = {
        enabled: true,
      };
      expect(config.enabled).toBe(true);
    });

    it("should accept minSavingsTokens option", () => {
      const config: PruningConfig = {
        minSavingsTokens: 200,
      };
      expect(config.minSavingsTokens).toBe(200);
    });

    it("should accept protectedToolNames option", () => {
      const config: PruningConfig = {
        protectedToolNames: ["protected1"],
      };
      expect(config.protectedToolNames).toEqual(["protected1"]);
    });

    it("should accept protectRecentTokens option", () => {
      const config: PruningConfig = {
        protectRecentTokens: 2000,
      };
      expect(config.protectRecentTokens).toBe(2000);
    });

    it("should accept replacementText option", () => {
      const config: PruningConfig = {
        replacementText: "[output pruned — too large]",
      };
      expect(config.replacementText).toBe("[output pruned — too large]");
    });

    it("should reject when required fields are missing", () => {
      // @ts-expect-error - all fields are optional
      const invalidConfig: PruningConfig = {};
      expect(invalidConfig).toBeDefined();
    });

    it("should have correct types for each field", () => {
      expectTypeOf<PruningConfig["eagerPruneToolNames"]>().toEqualTypeOf<string[] | undefined>();
      expectTypeOf<PruningConfig["enabled"]>().toEqualTypeOf<boolean | undefined>();
      expectTypeOf<PruningConfig["minSavingsTokens"]>().toEqualTypeOf<number | undefined>();
      expectTypeOf<PruningConfig["protectedToolNames"]>().toEqualTypeOf<string[] | undefined>();
      expectTypeOf<PruningConfig["protectRecentTokens"]>().toEqualTypeOf<number | undefined>();
      expectTypeOf<PruningConfig["replacementText"]>().toEqualTypeOf<string | undefined>();
    });

    it("should support default values through config", () => {
      const config: PruningConfig = {
        eagerPruneToolNames: [],
        enabled: false,
        minSavingsTokens: 200,
        protectedToolNames: [],
        protectRecentTokens: 2000,
        replacementText: "[output pruned — too large]",
      };
      expect(config.eagerPruneToolNames).toEqual([]);
      expect(config.enabled).toBe(false);
      expect(config.minSavingsTokens).toBe(200);
      expect(config.protectedToolNames).toEqual([]);
      expect(config.protectRecentTokens).toBe(2000);
      expect(config.replacementText).toBe("[output pruned — too large]");
    });
  });

  // ============================================
  // 6. ContinuationVariant Type
  // ============================================
  describe("ContinuationVariant", () => {
    it("should accept 'manual' value", () => {
      const variant: ContinuationVariant = "manual";
      expect(variant).toBe("manual");
    });

    it("should accept 'auto-with-replay' value", () => {
      const variant: ContinuationVariant = "auto-with-replay";
      expect(variant).toBe("auto-with-replay");
    });

    it("should accept 'tool-loop' value", () => {
      const variant: ContinuationVariant = "tool-loop";
      expect(variant).toBe("tool-loop");
    });

    it("should have correct type", () => {
      expectTypeOf<ContinuationVariant>().toEqualTypeOf<"manual" | "auto-with-replay" | "tool-loop">();
    });

    it("should reject invalid values", () => {
      // @ts-expect-error - invalid value
      const invalidVariant: ContinuationVariant = "invalid";
      expect(invalidVariant).toBeDefined();
    });
  });

  // ============================================
  // 7. CompactionResult Interface
  // ============================================
  describe("CompactionResult", () => {
    it("should have required success field", () => {
      const result: CompactionResult = {
        success: true,
        tokensAfter: 1000,
        tokensBefore: 5000,
      };
      expect(result.success).toBe(true);
      expect(result.tokensAfter).toBe(1000);
      expect(result.tokensBefore).toBe(5000);
    });

    it("should accept optional continuationVariant", () => {
      const result: CompactionResult = {
        success: true,
        tokensAfter: 1000,
        tokensBefore: 5000,
        continuationVariant: "manual",
      };
      expect(result.continuationVariant).toBe("manual");
    });

    it("should accept optional reason", () => {
      const result: CompactionResult = {
        success: false,
        tokensAfter: 5000,
        tokensBefore: 5000,
        reason: "Insufficient tokens to compact",
      };
      expect(result.reason).toBe("Insufficient tokens to compact");
    });

    it("should accept optional summaryMessageId", () => {
      const result: CompactionResult = {
        success: true,
        tokensAfter: 1000,
        tokensBefore: 5000,
        summaryMessageId: "summary-123",
      };
      expect(result.summaryMessageId).toBe("summary-123");
    });

    it("should have correct types for each field", () => {
      expectTypeOf<CompactionResult["success"]>().toEqualTypeOf<boolean>();
      expectTypeOf<CompactionResult["continuationVariant"]>().toEqualTypeOf<ContinuationVariant | undefined>();
      expectTypeOf<CompactionResult["reason"]>().toEqualTypeOf<string | undefined>();
      expectTypeOf<CompactionResult["summaryMessageId"]>().toEqualTypeOf<string | undefined>();
      expectTypeOf<CompactionResult["tokensAfter"]>().toEqualTypeOf<number>();
      expectTypeOf<CompactionResult["tokensBefore"]>().toEqualTypeOf<number>();
    });

    it("should reject when required fields are missing", () => {
      // @ts-expect-error - missing required fields
      const invalidResult: CompactionResult = {};
      expect(invalidResult).toBeDefined();
    });
  });

  // ============================================
  // 8. PreparedCompactionV2 Interface
  // ============================================
  describe("PreparedCompactionV2", () => {
    it("should have all required fields", () => {
      const compaction: PreparedCompactionV2 = {
        baseMessageIds: ["msg-1", "msg-2"],
        revision: 1,
        splitIndex: 5,
        summaryText: "summary",
        tokenDelta: -1000,
      };
      expect(compaction.baseMessageIds).toEqual(["msg-1", "msg-2"]);
      expect(compaction.revision).toBe(1);
      expect(compaction.splitIndex).toBe(5);
      expect(compaction.summaryText).toBe("summary");
      expect(compaction.tokenDelta).toBe(-1000);
    });

    it("should accept optional replayMessage", () => {
      const compaction: PreparedCompactionV2 = {
        baseMessageIds: ["msg-1"],
        revision: 1,
