      const input3: ActualTokenUsageInput = {
        totalTokens: 150,
      };
      expect(input1.completionTokens).toBe(100);
      expect(input2.promptTokens).toBe(50);
      expect(input3.totalTokens).toBe(150);
    });

    it("StructuredState should accept empty metadata and todos", () => {
      const state1: StructuredState = { metadata: {} };
      const state2: StructuredState = { todos: [] };
      expect(state1.metadata).toEqual({});
      expect(state2.todos).toEqual([]);
    });
  });
